# Surface category + sub_category on the all_platform_inventory view. They come
# from master_sheet (matched on the platform SKU code) via the view's existing
# master_lookup CTE -- exactly where item/item_head/brand already come from --
# so they stay in sync with master_sheet automatically and need no changes to the
# per-platform inventory base tables.
FORWARD_VIEW = " WITH master_lookup AS (\n         SELECT ranked.format,\n            ranked.format_sku_code,\n            ranked.item,\n            ranked.item_head,\n            ranked.brand,\n            ranked.per_unit_value,\n            ranked.category,\n            ranked.sub_category,\n            ranked.format_key,\n            ranked.sku_key\n           FROM ( SELECT ms.format,\n                    ms.format_sku_code,\n                    ms.item,\n                    ms.item_head,\n                    ms.brand,\n                    ms.per_unit_value,\n                    ms.category,\n                    ms.sub_category,\n                    regexp_replace(lower(TRIM(BOTH FROM COALESCE(ms.format, ''::text))), '[^a-z0-9]+'::text, ''::text, 'g'::text) AS format_key,\n                    upper(TRIM(BOTH FROM ms.format_sku_code::text)) AS sku_key,\n                    row_number() OVER (PARTITION BY (regexp_replace(lower(TRIM(BOTH FROM COALESCE(ms.format, ''::text))), '[^a-z0-9]+'::text, ''::text, 'g'::text)), (upper(TRIM(BOTH FROM ms.format_sku_code::text))) ORDER BY (\n                        CASE\n                            WHEN NULLIF(TRIM(BOTH FROM COALESCE(ms.item, ''::text)), ''::text) IS NULL THEN 1\n                            ELSE 0\n                        END), (\n                        CASE\n                            WHEN ms.per_unit_value IS NULL THEN 1\n                            ELSE 0\n                        END), (COALESCE(ms.product_name, ''::text)), ms.ctid) AS rn\n                   FROM master_sheet ms\n                  WHERE NULLIF(TRIM(BOTH FROM ms.format_sku_code::text), ''::text) IS NOT NULL) ranked\n          WHERE ranked.rn = 1\n        )\n SELECT bi.inventory_date,\n    bi.item_id AS sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    bi.total_inv_qty AS soh_unit,\n    bi.total_inv_qty::double precision * ms.per_unit_value AS soh_ltr,\n    bi.backend_facility_name AS location,\n    'BLINKIT'::text AS format,\n    ms.category,\n    ms.sub_category\n   FROM blinkit_inventory bi\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM bi.item_id)) = ms.sku_key AND ms.format_key = 'blinkit'::text\nUNION ALL\n SELECT zi.inventory_date,\n    zi.sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    zi.units AS soh_unit,\n    zi.units::double precision * ms.per_unit_value AS soh_ltr,\n    zi.city AS location,\n    'ZEPTO'::text AS format,\n    ms.category,\n    ms.sub_category\n   FROM zepto_inventory zi\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM zi.sku_code)) = ms.sku_key AND ms.format_key = 'zepto'::text\nUNION ALL\n SELECT sw.inventory_date,\n    sw.sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    sw.warehouse_qty_available AS soh_unit,\n    sw.warehouse_qty_available::double precision * ms.per_unit_value AS soh_ltr,\n    sw.city AS location,\n    'SWIGGY'::text AS format,\n    ms.category,\n    ms.sub_category\n   FROM swiggy_inventory sw\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM sw.sku_code)) = ms.sku_key AND ms.format_key = 'swiggy'::text\nUNION ALL\n SELECT bb.inventory_date,\n    bb.sku_id AS sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    bb.soh AS soh_unit,\n    bb.soh::double precision * ms.per_unit_value AS soh_ltr,\n    bb.city AS location,\n    'BIG BASKET'::text AS format,\n    ms.category,\n    ms.sub_category\n   FROM bigbasket_inventory bb\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM bb.sku_id)) = ms.sku_key AND ms.format_key = 'bigbasket'::text\nUNION ALL\n SELECT jio.inventory_date,\n    jio.sku_id AS sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    jio.total_sellable_inv AS soh_unit,\n    jio.total_sellable_inv::double precision * ms.per_unit_value AS soh_ltr,\n    jio.rfc_name AS location,\n    'JIO MART'::text AS format,\n    ms.category,\n    ms.sub_category\n   FROM jiomart_inventory jio\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM jio.sku_id)) = ms.sku_key AND ms.format_key = 'jiomart'::text"
REVERSE_VIEW = " WITH master_lookup AS (\n         SELECT ranked.format,\n            ranked.format_sku_code,\n            ranked.item,\n            ranked.item_head,\n            ranked.brand,\n            ranked.per_unit_value,\n            ranked.format_key,\n            ranked.sku_key\n           FROM ( SELECT ms.format,\n                    ms.format_sku_code,\n                    ms.item,\n                    ms.item_head,\n                    ms.brand,\n                    ms.per_unit_value,\n                    regexp_replace(lower(TRIM(BOTH FROM COALESCE(ms.format, ''::text))), '[^a-z0-9]+'::text, ''::text, 'g'::text) AS format_key,\n                    upper(TRIM(BOTH FROM ms.format_sku_code::text)) AS sku_key,\n                    row_number() OVER (PARTITION BY (regexp_replace(lower(TRIM(BOTH FROM COALESCE(ms.format, ''::text))), '[^a-z0-9]+'::text, ''::text, 'g'::text)), (upper(TRIM(BOTH FROM ms.format_sku_code::text))) ORDER BY (\n                        CASE\n                            WHEN NULLIF(TRIM(BOTH FROM COALESCE(ms.item, ''::text)), ''::text) IS NULL THEN 1\n                            ELSE 0\n                        END), (\n                        CASE\n                            WHEN ms.per_unit_value IS NULL THEN 1\n                            ELSE 0\n                        END), (COALESCE(ms.product_name, ''::text)), ms.ctid) AS rn\n                   FROM master_sheet ms\n                  WHERE NULLIF(TRIM(BOTH FROM ms.format_sku_code::text), ''::text) IS NOT NULL) ranked\n          WHERE ranked.rn = 1\n        )\n SELECT bi.inventory_date,\n    bi.item_id AS sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    bi.total_inv_qty AS soh_unit,\n    bi.total_inv_qty::double precision * ms.per_unit_value AS soh_ltr,\n    bi.backend_facility_name AS location,\n    'BLINKIT'::text AS format\n   FROM blinkit_inventory bi\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM bi.item_id)) = ms.sku_key AND ms.format_key = 'blinkit'::text\nUNION ALL\n SELECT zi.inventory_date,\n    zi.sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    zi.units AS soh_unit,\n    zi.units::double precision * ms.per_unit_value AS soh_ltr,\n    zi.city AS location,\n    'ZEPTO'::text AS format\n   FROM zepto_inventory zi\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM zi.sku_code)) = ms.sku_key AND ms.format_key = 'zepto'::text\nUNION ALL\n SELECT sw.inventory_date,\n    sw.sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    sw.warehouse_qty_available AS soh_unit,\n    sw.warehouse_qty_available::double precision * ms.per_unit_value AS soh_ltr,\n    sw.city AS location,\n    'SWIGGY'::text AS format\n   FROM swiggy_inventory sw\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM sw.sku_code)) = ms.sku_key AND ms.format_key = 'swiggy'::text\nUNION ALL\n SELECT bb.inventory_date,\n    bb.sku_id AS sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    bb.soh AS soh_unit,\n    bb.soh::double precision * ms.per_unit_value AS soh_ltr,\n    bb.city AS location,\n    'BIG BASKET'::text AS format\n   FROM bigbasket_inventory bb\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM bb.sku_id)) = ms.sku_key AND ms.format_key = 'bigbasket'::text\nUNION ALL\n SELECT jio.inventory_date,\n    jio.sku_id AS sku_code,\n    ms.item,\n    ms.item_head,\n    ms.brand,\n    jio.total_sellable_inv AS soh_unit,\n    jio.total_sellable_inv::double precision * ms.per_unit_value AS soh_ltr,\n    jio.rfc_name AS location,\n    'JIO MART'::text AS format\n   FROM jiomart_inventory jio\n     JOIN master_lookup ms ON upper(TRIM(BOTH FROM jio.sku_id)) = ms.sku_key AND ms.format_key = 'jiomart'::text"


